int main() {
    EVP_PKEY *pkey = NULL;
    EVP_PKEY_CTX *ctx = EVP_PKEY_CTX_new_id(EVP_PKEY_RSA, NULL);
    if (!ctx) return 1;

    // 1. Generate a 2048-bit RSA key using EVP high-level APIs
    if (EVP_PKEY_keygen_init(ctx) <= 0) {
        EVP_PKEY_CTX_free(ctx);
        return 1;
    }
    if (EVP_PKEY_CTX_set_rsa_keygen_bits(ctx, 2048) <= 0) {
        EVP_PKEY_CTX_free(ctx);
        return 1;
    }
    if (EVP_PKEY_keygen(ctx, &pkey) <= 0) {
        EVP_PKEY_CTX_free(ctx);
        return 1;
    }

    // 2. Sign the SHA-256 digest of a message
    const char *message = "Security Engineering Fact Check";
    size_t message_len = strlen(message);
    size_t sig_len = 0;
    unsigned char *sig = NULL;

    // Fetch SHA-256 explicitly as recommended for OpenSSL 3.0
    EVP_MD *md = EVP_MD_fetch(NULL, "SHA256", NULL);
    EVP_MD_CTX *md_ctx = EVP_MD_CTX_new();

    if (EVP_DigestSignInit(md_ctx, md, NULL, pkey) <= 0) {
        EVP_MD_free(md);
        EVP_MD_CTX_free(md_ctx);
        EVP_PKEY_free(pkey);
        EVP_PKEY_CTX_free(ctx);
        return 1;
    }

    // Determine buffer size
    if (EVP_DigestSign(md_ctx, NULL, &sig_len, (const unsigned char *)message, message_len) <= 0) {
        return 1;
    }

    sig = OPENSSL_malloc(sig_len);
    if (EVP_DigestSign(md_ctx, sig, &sig_len, (const unsigned char *)message, message_len) <= 0) {
        return 1;
    }

    printf("Signature generated (%zu bytes).\n", sig_len);

    // 3. Extract the modulus n as a BIGNUM
    // EVP_PKEY_get0_RSA returns a const pointer in OpenSSL 3.0
    const RSA *rsa = EVP_PKEY_get0_RSA(pkey);
    if (rsa != NULL) {
        BIGNUM *n = rsa->n; 
        printf("Modulus (n):\n");
        print_01_bn(n);
    }

    // Cleanup
    EVP_MD_free(md);
    EVP_MD_CTX_free(md_ctx);
    EVP_PKEY_free(pkey);
    EVP_PKEY_CTX_free(ctx);
    OPENSSL_free(sig);

    return 0;
}
